patch:
--- a/comparator_32bit.v
+++ b/comparator_32bit.v
@@ -6,8 +6,8 @@
   output reg lt
 );

-  always @(bus_a or bus_b) begin
-    eq = (bus_a == bus_b);
-    gt = (bus_a > bus_b);
-    lt = (bus_a < bus_b);
+  always @(*) begin
+    eq <= (bus_a == bus_b);
+    gt <= (bus_a > bus_b);
+    lt <= (bus_a < bus_b);

before_code:
module comparator_32bit(
  input [31:0] bus_a,
  input [31:0] bus_b,
  output reg eq,
  output reg gt,
  output reg lt
);

  always @(bus_a or bus_b) begin
    eq = (bus_a == bus_b);
    gt = (bus_a > bus_b);
    lt = (bus_a < bus_b);
  end

endmodule

after_code:
module comparator_32bit(
  input [31:0] bus_a,
  input [31:0] bus_b,
  output reg eq,
  output reg gt,
  output reg lt
);

  always @(*) begin
    eq = (bus_a == bus_b);
    gt = (bus_a > bus_b);
    lt = (bus_a < bus_b);
  end

endmodule
